        ["options_header_set_collections"]              = "Set collections",
        ["options_enable_auto_mark_sets_collection"]    = "Automatic \'Set collection\' marking",
        ["options_enable_auto_mark_sets_collection_TT"] = "Enable automatic \'Set collection\' marker icons",
        ["options_only_current_account"]                = "Only current account",
        ["options_only_current_account_TT"]             = "Only use currently logged in account for the checks",
        ["options_auto_mark_sets_collection_addon"]     = "Addon for \'Set collection\' checks",
        ["options_auto_mark_sets_collection_addon_TT"]  = "Choose the addon which should be used for the automatic set collection checks (known/unknown collected set items).\nThe ESO standard is not able to support other accounts as the currently logged in!",
        ["options_auto_mark_sets_collection_known_icon"]    = "Known set collection item icon",
        ["options_auto_mark_sets_collection_known_icon_TT"] = "Choose the icon for known set collection items.",
        ["options_auto_mark_sets_collection_unknown_icon"]    = "Unknown set collection item icon",
        ["options_auto_mark_sets_collection_unknown_icon_TT"] = "Choose the icon for unknown set collection items.",

        ["options_description_automatic_marks"] = "Automatics Markings applies icons markers automatically to your items, depending on your defined criteria. E.g. mark set items which got a desired trait (precise, divine, ...) with a desired marker icon, and mark all others with the sell/deconstruct icon. Or mark unknown recipies. The Automatic markings may depend on other addons which you may need to install and setup.\nAutomatic markings will be internally checked and applied at each login/reloadui/zone change with loading screen for all items in all of your inventories!\nYou are also able to manually trigger them via the additional inventory \'flag\' "..addInvFlagIcon.." icons at the inventories -> sub context menu \'Automatic markings\'. Attention: Triggering it from the flag icon will ONLY apply the markings to the currently visible (filtered) items, and not all of your selected inventories (see submenu \'Inv. bags to scan\') and items!\n\nPlease read the tooltips of each setting in the Automatic markings submenus carefully!\n\nThe order of verification and applied Automatic markings is as follows::\n1) Set items\n2) Set collections\n3) Ornate\n4) Intricate\n5) Research\n6) Research scrolls\n7) Unknown recipes\n8) Known recipes\n9) Quality\nCrafted and new Automatic markings are special and will only be applied as the item is crafted by you or a new item enters your inventory.",
        ["options_known"] = "known",
        ["options_bags_to_scan"]                        = "Inv. bags to scan",
        ["options_bags_to_scan_automatic_marks_TT"]     = "Inventory bags to scan for automatic marking as a ReloadUI/zone change with loading screen is done/items get into your inventory (loot).\nManually triggered automatic markings via the add. inv. "..addInvFlagIcon.." context menu will only scan the currently visible items at the currently opened inventory, and as you manually trigger them they will scan the currently visible bag even if it is disabled below!",
        ["options_bags_to_scan_order"]                  = "Scan order",
        ["options_bags_to_scan_order_TT"]               = "Choose the scan order for the inventory bags. Automatic markings scans will be processed and marked for the enabled \'Inv. bags to scan\' according to your scan order [from top 1) to bottom n)].",
        ["options_scan_automatic_marks_now"]            = "Scan autom. mark.",
        ["options_scan_automatic_marks_now_TT"]         = "Scan the chosen invenories now for the automatic markings that can be applied",
        ["options_scan_automatic_marks_scan_bag"]           = ">>>Scanning \'%s\' for Automatic Markings...",
        ["options_scan_automatic_marks_scan_bag_finished"]  = "Scan of \'%s\' was finished<<<",
        ["options_bags_to_scan_chat_output"]             = "Show bag scan chat output",
        ["options_bags_to_scan_chat_output_TT"]          = "Show a chat output of each scanned bag, as the scanning of the bag starts and ends. Marked items will be shown in the chat depending on each markings-submenu settings, independent on this setting here.",
        ["reloadui"] = "CAUTION: The user interface will be reloaded in %s seconds!",

        ["options_auto_bind_missing_set_collection_pieces"] = "Auto bind missing pieces",
        ["options_auto_bind_missing_set_collection_pieces_TT"] = "Auto bind missing set collection pieces to your account.\nBound items will still get the \'unknown marker icon\' applied so you are able to filter them acordingly.\nOnly works with vanilla ESO missing set collection piece detection and with the logged in account!\n\nThis will be done each time the automatic set collection piece marks get applied (manually or upon looting items).\n\n|cFF0000Attention:|r There will be NO security dialog asking up in front if the item should be bound!",
        ["options_auto_bind_missing_set_collection_pieces_to_chat"] = "Show in chat",
        ["options_auto_bind_missing_set_collection_pieces_to_chat_TT"] = "Show the items that were auto bound in the chat",
        ["chat_output_missing_set_collection_piece_was_bound"] = "Missing set collection piece was bound: %s",

