	--German / Deutsch
    [FCOIS_CON_LANG_DE] = {
        -- Options menu
        ["options_description_lam_menu_is_loading"] = "|cFF0000!!!ACHTUNG!!!\n\nDas FCOIS Einstellungsmen√ľ wird gerade geladen. Bitte warten und keine Einstellungen ver√§ndern bis dieses Symbol verschwindet!\n\nESO kann f√ľr einige Sekunden schlecht reagieren.\nSobald alle Einstellungen erstellt wurden verschwindet dieses Symbol und Sie k√∂nnen mit den Einstellungen arbeiten.",
        ["options_description"] 				 = "FCOItemSaver verschafft Ihnen mit Hilfe von Symbolen einen √úberblick √ľber Ihre Gegenst√§nde und l√§sst Sie diese bequem ein-/ausblenden & absichern",
        ["options_header1"] 			 		 = "Generelle Einstellungen",
        ["options_language"] 					 = "Sprache",
