        ["options_language_dropdown_selection7"] = "Russisch",
        ["options_language_description1"]		 = "ACHTUNG: Ver√§nderungen der Sprache/der Speicherart laden die Benutzeroberfl√§che neu!",
        ["options_savedvariables"]				 = "Einstellungen speichern",
        ["options_savedvariables_TT"]       = "Die Einstellungen dieses Addons werden f√ľr alle Charactere Ihres Accounts, oder f√ľr jeden Character einzeln gespeichert",
        ["options_savedVariables_dropdown_selection1"] = "Jeder Charakter",
        ["options_savedVariables_dropdown_selection2"] = "Ganzer Account",
        ["options_savedVariables_dropdown_selection3"] = "Alle Accounts gleich",

        ["options_header_copy_sv"]              =   "Kopiere SavedVariables",
        ["options_copy_sv_source_server"]       =   "Quell-Server",
        ["options_copy_sv_target_server"]        =  "Ziel-Server",
        ["options_description_copy_sv_server"]  = "|cff0000Vor dem Kopieren/L√∂schen von SavedVariables LOG DICH bitte AUS und KOPIERE die SavedVariables DATEI 'FCOItemSaver.lua' ALS BACKUP! Klicke auf den '|c5959D5Feedback|r|cff0000' Link oben und dann auf den 'FAQ' Knopf, um eine Erkl√§rung zu erhalten, wie du die Backup Datei erstellen kannst.|r\n\nKopiere SavedVariables von einem Server zu einem anderen. W√§hlen den Account oder Charakter weiter unten aus. Kopieren oder L√∂schen der Daten eines gesamten Servers ist nicht m√∂glich!",
        --["options_copy_sv_to_server"]           =   "Copy to server",
        --["options_copy_sv_to_server_TT"]   =   "Copy the SavedVariables from the chosen source server to the chosen target sever. Copying from a source to the same target server is not possible!\nIf you are using account wide setings, or all accounts use the same settings, all data will be transfered.\nIf you are using character settings only your currently logged in character will be transfered.\n\nAttention: Existing target data will be overwritten!",
        ["options_copy_sv_to_server_warning"]   =   "Willst du wirklich die SavedVariables kopieren?\nExistierende Ziel-Daten werden √ľberschrieben!\n\nWenn du auf dem Ziel-Server eingeloggt bist wird deine Benutzeroberfl√§che im Anschlu√ü neu laden!",
        ["question_copy_sv_server_reloadui"]    = "SavedVariables wurden von Server \"<<C:1>>\" zu Server \"<<C:2>>\" kopiert, Accountweite Einstellungen: <<3>>.\n\nDa du aktuell auf dem Ziel-Server eingeloggt bist:\nBenutzeroberfl√§che neu laden?",
        ["question_delete_sv_server_reloadui"]   = "SavedVariables von Server \"<<C:1>>\" gel√∂scht, Accountweite Einstellungen: <<2>>.\n\nDa du aktuell auf dem Ziel-Server eingeloggt bist:\nBenutzeroberfl√§che neu laden?",
        --["options_delete_sv_on_server"]           =   "Delete target server",
        --["options_delete_sv_on_server_TT"]   =   "Delete the SavedVariables on the target server.\nIf you are logged in to the target server with the chosen target account and character your user UI will reload afterwards!\n\nAttention: Existing target data will be deleted without any backup!",

        ["options_description_copy_sv_account"]  = "Diese Option ist nur verf√ľgbar, wenn ein Server gew√§hlt wurde. |c75daffBitte lies die Tooltips an den Account kopieren/l√∂schen Kn√∂pfen!|r",
        ["options_copy_sv_source_account"]       =   "Quell-Account",
        ["options_copy_sv_target_account"]        =   "Ziel-Account",
        ["options_copy_sv_to_account"]           =   "Kopiere zu Account",
        ["options_copy_sv_to_account_TT"]   =   "Kopiere die SavedVariables vom ausgew√§hlten Quell-Server und Quell-Account zum gew√§hlten Ziel-Server und Ziel-Account. Quell- und Ziel-Server k√∂nnen identisch sein, aber Quell- und Ziel-Account m√ľssen unterschiedlich sein.\n\nOder kopiere einen Quell-Server & Quell-Account & Quell-Charakter->zu einem Ziel-Server & Ziel-Account. Quell- und Ziel-Server, sowie Quell- und Ziel-Account, k√∂nnen dabei dann identisch sein.\n\nAchtung: Existierende Ziel-Daten werden √ľberschrieben!",
        ["options_copy_sv_to_account_warning"]   =   "Willst du wirklich die SavedVariables kopieren?\nExistierende Ziel-Daten werden √ľberschrieben!\n\nWenn du auf dem Ziel-Server mit dem Ziel-Account eingeloggt bist, wird die Benutzeroberfl√§che im Anschluss neugeladen werden!",
        ["question_copy_sv_account_reloadui"]           = "SavedVariables von Server \"<<C:1>>\" Account \"<<C:2>>\" zu Server \"<<C:3>>\" Account \"<<C:4>>\" kopiert, Accountweite Einstellungen: <<5>>.\n\nDa du aktuell auf dem Ziel-Server eingeloggt bist:\nBenutzeroberfl√§che neu laden?",
        ["question_delete_sv_account_reloadui"]   = "SavedVariables von Server \"<<C:1>>\" Account \"<<C:2>>\" gel√∂scht, Accountweite Einstellungen: <<3>>.\n\nDa du aktuell auf dem Ziel-Server eingeloggt bist:\nBenutzeroberfl√§che neu laden?",
        ["options_delete_sv_account"]           =   "L√∂sche Ziel-Account",
        ["options_delete_sv_account_TT"]   =   "L√∂scht die SavedVariables auf dem Ziel-Server und Ziel-Account.\nWenn du auf dem Ziel-Server mit dem Ziel-Account und Ziel-Charakter eingeloggt bist, wird die Benutzeroberfl√§che im Anschluss neugeladen werden!\n\nAchtung: Existierende Ziel-Daten werden ohne Backup gel√∂scht!",

        ["options_description_copy_sv_character"]  = "Diese Option ist nur verf√ľgbar, wenn ein Account ausgew√§hlt wurde (au√üer 'Alle Accounts gleich'). Du musst in der Vergangenheit bereits Charaktere mit der Einstellung 'Jeder Charakter' gespeichert haben, um diese Charaktere in der Quell-Charakter Liste weiter unten ausw√§hlen zu k√∂nnen. |c75daffBitte lies die Tooltips der Kopieren/L√∂schen Kn√∂pfe!|r",
        ["options_copy_sv_source_character"]       =   "Quell-Charakter",
        ["options_copy_sv_target_character"]        =   "Ziel-Charakter",
        ["options_copy_sv_to_character"]           =   "Kopiere zu Charakter",
        ["options_copy_sv_to_character_TT"]   =   "Kopiere die SavedVariables vom ausgew√§hlten Quell-Server und Quell-Account und Quell-Charakter zum ausgew√§hlten Ziel-Server, Ziel-Account und Ziel-Charakter. Quell- und Ziel-Server sowie Quell- und Ziel-Account k√∂nnen dabei identisch sein, jedoch m√ľssen Quell- und Ziel-Charakter unterschiedlich sein!\nDu musst in der Vergangenheit in den 'Generellen Einstellungen' die Option 'Einstellungen speichern' mit der Auswahl 'Jeder Charakter' aktiviert haben, damit die mit dieser Einstellung bereits eingeloggten Charaktere in der Quell-Charakter Liste ausgew√§hlt werden k√∂nnen!\n\nOder kopiere einen Quell-Server & Quell-Account zu einem Ziel-Server & Ziel-Account & Ziel-Charakter. Quell- und Ziel-Server, sowie Quell- und Ziel-Account, k√∂nnen dabei dann identisch sein.\n\nAchtung: Existierende Ziel-Daten werden √ľberschrieben!",
        ["options_copy_sv_to_character_warning"]   =   "Willst du wirklich die SavedVariables kopieren?\nExistierende Ziel-Daten werden √ľberschrieben!\n\nWenn du auf dem Ziel-Server mit dem Ziel-Account und Ziel-Charakter eingeloggt bist wird deine Benutzeroberfl√§che im Anschlu√ü neu laden!",
        ["question_copy_sv_character_reloadui"]   = "SavedVariables von Server \"<<C:1>>\" Account \"<<C:2>>\" Charakter \"<<C:3>>\" zu Server \"<<C:4>>\" Account \"<<C:5>>\" Charakter \"<<C:6>>\" kopiert, Accountweite Einstellungen: <<7>>.\n\nDa du aktuell auf dem Ziel-Server eingeloggt bist:\nBenutzeroberfl√§che neu laden?",
        ["question_delete_sv_character_reloadui"]   = "SavedVariables von Server \"<<C:1>>\" Account \"<<C:2>>\" Charakter \"<<C:3>>\" gel√∂scht, Accountweite Einstellungen: <<4>>.\n\nDa du aktuell auf dem Ziel-Server eingeloggt bist:\nBenutzeroberfl√§che neu laden?",
        ["options_delete_sv_character"]           =   "L√∂sche Ziel-Charakter",
        ["options_delete_sv_character_TT"]   =   "L√∂scht den Ziel-Charakter in den SavedVariables auf dem Ziel-Server, Ziel-Account.\nWenn du auf dem Ziel-Server mit dem Ziel-Account und Ziel-Charakter eingeloggt bist wird deine Benutzeroberfl√§che im Anschlu√ü neu laden!\n\n\nAchtung: Existierende Ziel-Daten werden gel√∂scht!",

        ["question_copy_sv_account_to_char_reloadui"]  = "SavedVariables vom Server \"<<C:1>>\" Account \"<<C:2>>\" zum Server \"<<C:3>>\" Account \"<<C:4>>\" Charakter \"<<C:5>>\" kopiert, Accountweite Einstellungen: <<6>>.\n\nDa du aktuell auf dem Ziel-Server eingeloggt bist:\nBenutzeroberfl√§che neu laden?",
        ["question_copy_sv_char_to_account_reloadui"]  = "SavedVariables vom Server \"<<C:1>>\" Account \"<<C:2>>\" Charakter \"<<C:3>>\" zum Server \"<<C:4>>\" Account \"<<C:5>>\" kopiert, Accountweite Einstellungen: <<6>>.\n\nDa du aktuell auf dem Ziel-Server eingeloggt bist:\nBenutzeroberfl√§che neu laden?",
        ["options_copy_sv_account_to_char"] = "Kopiere Account->Char",
        ["options_copy_sv_char_to_account"] = "Kopiere Char->Account",


        ["options_hint_backup_savedvariables_file_title"] = "Backup SavedVariables!",
        ["options_hint_backup_savedvariables_file"] = "Bitte logge dich aus und erstelle\n ein Backup von deiner 'FCOItemSaver.lua'\n SavedVariables Datei, bevor du mit den\n SavedVariable Kopier/L√∂schen Optionen arbeitest!\n\nHast du bereits ein Backup erstellt, dann dr√ľcke bitte jetzt den Knopf \'Abbrechen\' und f√ľhre die Aktion erneut aus.\nDieser Dialog wird dann nicht mehr angezeigt!",

        ["options_header_uniqueids"]           = "Eindeutige Gegenstand ID",
        ["options_description_uniqueids"]       = "Deine Gegenst√§nde im Spiel besitzen eine ID. Diese ID ist f√ľr alle Gegenst√§nde mit √§hnlichen Grunddaten identisch (nicht-eindeutige ID), z.B. Name, Level und Qualit√§t. Ein Dietrich und ein gestohlener Dietrich z.B. w√§ren solche identischen Grunddaten Gegenst√§nde. Diese nicht-eindeutigen IDs verwendet FCO ItemSaver als Standard, um die Markierungen an Gegenst√§nden zu setzen und sich zu merken (die sogenannte \'ItemInstanceId\')!\n\nJeder Gegenstand besitzt aber auch noch eine eindeutige ID (die sogenannte \'UniqueId\'). Bei dieser werden Verzauberungen, Level, Stil, Trait, etc. diese eindeutige ID ver√§ndern! Eindeutige Gegenstand IDs erlauben es dir daher Gegenst√§nde mit √§hnlichen Grunddaten unterschiedlich zu markieren, aber dies verlangt, dass du eben alle diese eindeutigen Gegenst√§nde wieder neu markieren musst, wenn sie in einer noch nicht markierten Kombination in dein Inventar gelangen.\n\nDu hast hier die nicht eindeutige ItemInstance-ID, sowie mehrere Typen der Unique-IDs zur Auswahl, um die Markierungen an deinen Gegenst√§nden zu speichern. |c75daffBitte lies die Tooltips der Eintr√§ge (Aufklappbox aufklappen -> Maus √ľber die Eintr√§ge bewegen) in der Aufklappbox \'Typ der eindeutigen ID\', um die Unterschiede der eindeutigen IDs zu erfahren. Du musst den Haken bei \'Nutze eindeutige Gegenstands IDs\' setzen, damit die Aufklappbox eingabebereit wird.|r\n\n|cFF0000Achtung: Das Ver√§ndern dieser Option l√§dt die Benutzeroberfl√§che neu (/reloadui)! Danach kannst du hier drunter deinen EindeutigenID Typ bestimmen.|r",
        ["options_use_uniqueids"]               = "Nutze eindeutige Gegenstands IDs",
        ["options_use_uniqueids_TT"]       = "Aktiviert:\nNutze eindeutige Gegenstand IDs.\n\nDeaktiviert:\nNutze die nicht-eindeutigen Gegenstand IDs und markiere alle Gegenst√§nde mit denselben Grunddaten identisch (itemInstanceId).\n\nAchtung: Deine bereits markierten Gegenst√§nde werden gesichert und wenn du zwischen den eindeutigen und nicht-eindeutigen Gegenstand IDs umschaltest, sind die Markierungen weiterhin vorhanden, und werden bei einem Wechsel dieser Einstellung wieder angezeigt. Die itemInstanceIds und EindeutigenIds k√∂nnen jedoch NICHT synchronisiert werden!\n\n|cFF0000Achtung: Die Benutzeroberfl√§che wird automatisch neuladen (/reloadui), wenn du diese Option ver√§ndert hast!|r",
        ["options_migrate_uniqueids"]           = "Migriere>EindeutigeID",
        ["options_migrate_uniqueids_TT"]   = "Migriere die markierten Gegenst√§nde von den nicht-eindeutigen zu den eindeutigen IDs.\nDies wird alle die Gegenst√§nde mit denselben Markierungs-Symbolen markieren, welche du vorher mit den nicht-eindeutigen Einstellungen bereits markiert hattest.\nSo werden alle Gegenst√§nde weiterhin gesichert und du musst die Markierungen nur √§ndern/entfernen.\n\n|cFF0000Diese Option ist solange deaktiviert, bis du die eindeutigen Gegenstand IDs aktiviert hast UND du die Benutzeroberfl√§che neugeladen (/reloadui) hast!\nNutze anschlie√üend das Migrations Popup, oder komme hierhin zur√ľck, um die Migration zu starten.|r",
        ["options_migrate_ids_migration_log"] = "|c75daffNach der Migration wird die Benutzeroberfl√§che automatisch, nach 3 Sekunden, neu geladen WENN ein Markierungssymbol migriert wurde! Ansonsten siehst du den Log direkt im Chat.\nNach diesem Neuladen bekommst du das Migrations Log im Chat einmalig angezeigt.|r",
        ["options_migrate_ids_migration_log_dialog"] = "|c75daffNach der Migration wird die Benutzeroberfl√§che\n automatisch, nach 3 Sekunden, neu geladen WENN\n ein Markierungssymbol migriert wurde!\nAnsonsten siehst du\n den Log direkt im Chat.\nNach diesem Neuladen bekommst du das Migrations\nLog einmalig im Chat angezeigt.|r",
        ["options_migrate_uniqueids_warning"]   = "Dies migriert alle Markierungen deiner nicht-eindeutigen Gegenstand IDs zu den eindeutigen IDs derselben Gegenst√§nden.\nExistierende Markierungen werden dabei nicht entfernt und neue werden lediglich hinzugef√ľgt!\n\nDiese Migration ist nicht umkehrbar! Du musst die migrierten Markierungen anschlie√üend selbst wieder entfernen.",
        ["options_migrate_unique_inv_scan_not_done"]   = "Du hast den Gegenstand Markierungs-Modus auf eindeutige IDs ge√§ndert.\nDie automatischen Markierungen werden daher 1x nicht durchgef√ľhrt, damit du die Migration deiner alten Markierungen nun starten kannst, wenn du m√∂chtest!",
        ["options_migrate_start"] = "Migration gestartet: <<1>>",
        ["options_migrate_results"] = "> Es <<1[wurde kein Symbol/wurde 1 Symbol/wurden $d Symbole]>> bei <<2[keinem Gegenstand/1 Gegenstand/$d Gegenst√§nden]>> migriert.",
        ["options_migrate_end"] = "Migration beendet: <<1>>",
        ["options_migrate_bag_type_" .. tostring(BAG_WORN)] = GetString(SI_BINDING_NAME_TOGGLE_CHARACTER),
