        ["options_migrate_bag_type_" .. tostring(BAG_SUBSCRIBER_BANK)] = GetString(SI_ESO_PLUS_TITLE) .. " " .. GetString(SI_GAMEPAD_BANK_CATEGORY_HEADER),
        ["options_migrate_bag_type_" .. tostring(BAG_HOUSE_BANK_ONE)] = GetString(SI_COLLECTIBLECATEGORYTYPE25) .. " 1",
