        ["options_migrate_bag_type_" .. tostring(BAG_HOUSE_BANK_TEN)] = GetString(SI_COLLECTIBLECATEGORYTYPE25) .. " 10",
        ["options_migrate_uniqueids_dialog"]   = "Migriere jetzt markierte nicht-eindeutige Gegenst√§nde\nzu eindeutigen?\n\nEs werden nur Markierungen hinzugef√ľgt.\nEs werden keine Markierungen entfernt.",
        ["options_migrate_nonuniqueids_dialog"]   = "Migriere jetzt markierte eindeutige Gegenst√§nde\nzu nicht-eindeutigen?\n\nEs werden nur Markierungen hinzugef√ľgt.\nEs werden keine Markierungen entfernt.",
        ["options_migrate_iteminstanceids"]     = "Migriere>ItemInstanceID",
        ["options_migrate_iteminstanceids_TT"]  = "Migriere die markierten Gegenst√§nde von den eindeutigen zu den nicht-eindeutigen IDs.\nDies wird alle die Gegenst√§nde mit denselben Markierungs-Symbolen markieren, welche du vorher mit den eindeutigen Einstellungen bereits markiert hattest.\nSo werden alle Gegenst√§nde weiterhin gesichert und du musst die Markierungen nur √§ndern/entfernen.\n\n|cFF0000Diese Option ist solange deaktiviert, bis du die nicht-eindeutigen Gegenstand IDs aktiviert hast UND du die Benutzeroberfl√§che neugeladen (/reloadui) hast!\nNutze anschlie√üend das Migrations Popup, oder komme hierhin zur√ľck, um die Migration zu starten.|r",
        ["options_migrate_iteminstanceids_warning"]   = "Dies migriert alle Markierungen deiner eindeutigen Gegenstand IDs zu den nicht-eindeutigen Ids derselben Gegenst√§nde.\nExistierende Markierungen werden dabei nicht entfernt und neue werden lediglich hinzugef√ľgt!\n\nDiese Migration ist nicht umkehrbar! Du musst die migrierten Markierungen anschlie√üend selbst wieder entfernen.",
        ["options_migrate_uniqueId_to_uniqueId"]        = "Migration des eindeutigen ID Typs: %s zum eindeutigen ID Typ: %s",
        ["options_migrate_uniqueId_to_non_uniqueId"]    = "Migration des eindeutigen ID Tys %s zu nicht-eindeutigen IDs",
        ["options_migrate_non_uniqueId_to_uniqueId"]    = "Migration der nicht-eindeutigen IDs zur eindeutigen ID des Typs: %s",

        ["options_header_ZOsLock"]                  = "ZOs Gegenstand-Sperre",
        ["options_use_ZOs_lock_functions"] 			= "Aktiviere TESO Gegenstand-Sperre " ..lockIcon,
        ["options_use_ZOs_lock_functions_TT"]	= "Aktiviere/Deaktiviere die vom Spiel-Programmierer ZOs mitgebrachte Gegenstand Sperre (graues Schloss Symbol "..lockIcon..").\nIst diese Option deaktiviert so wird der Eintrag im Kontextmen√ľ, als auch die Symbole, in den Inventaren versteckt.",
        ["options_scan_ZOs_lock_functions"]			= "TESO "..lockIcon.."->FCOIS "..lockIcon,
        ["options_scan_ZOs_lock_functions_TT"]      = "Transferiert die Gegenst√§nde, welche im Spiel mit der standard Gegenstandssperre (graues Schloss) gesch√ľtzt wurden zur FCOItemSaver \'Schlo√ü\' Markierung. D.h. die bisher durch das Spiel markierten, und dadurch gesch√ľtzten, Gegenst√§nde verlieren die Spiel-Markierung und werden auf das FCOIS Symbol 1 (Schloss Symbol) gewechselt, so dass diese Gegenst√§nde nun durch FCOIS umfangreicher gesch√ľtzt werden.\nBitte beachte, dass du dich in deinem Haus befinden musst, wenn du die Haus Banken mit migrieren m√∂chtest!\n\nGegenst√§nde werden in 50er Paketen gescannt. Dies dauert etwas. Bitte beachte den Chat!",
        ["options_scan_ZOs_lock_functions_warning"]	= "Wollen Sie wirklich den Gegenstands-Schutz vom Standard Schloss Symbol zum FCOItemSaver \'Schloss\' Symbol √ľbertragen?\n\nGegenst√§nde werden in 50er Paketen gescannt. Dies dauert etwas. Bitte beachte den Chat!",
        ["options_header_icon_options"]		 	 = "Symbol Position, Sortierung, etc.",
        ["options_header_marking_options"]		 = "Markierungen",
        ["options_header_crafting"]              = GetString(SI_SKILLTYPE8),
        ["options_remove_all_markers_with_shift_rightclick"]	= "Alle entfernen: <Mod. Taste> + |t100.000000%:100.000000%:EsoUI/Art/Miscellaneous/icon_RMB.dds|t",
        ["options_remove_all_markers_with_shift_rightclick_TT"]	= "Entferne alle Markierungen von einem Gegenstand, wenn du diesen mit der rechten Maustaste |t100.000000%:100.000000%:EsoUI/Art/Miscellaneous/icon_RMB.dds|t anklickst w√§hrend du die <Modifikator Taste> gedr√ľckt h√§ltst.\nWenn du die rechte Maustaste + <Modifikator Taste> erneut auf diesem Gegenstand dr√ľckst werden die letzten Markierungen wieder hergestellt.\n\nDies funktioniert nur bis zum n√§chsten Neuladen der Benutzeroberfl√§che/Logout!\n\nWenn manuelle Markierungen auf einem Gegenstand gesetzt/entfernt werden, der einen Undo Eintrag besitzt, so wird dieser Undo Eintrag geleert!",
        ["options_modifier_key"]			= "Modifikator Taste",
        ["options_modifier_key_TT"]         = "Die Modifikator Taste ALT, UMSCHALTEN, STRG or COMMAND (nur auf MAC!)",
        ["KEY_SHIFT"] = "Umschalten/Shift",
