        ["KEY_CTRL"] = "Steuerung/STRG",
        ["KEY_COMMAND"] = "Command (Nur MAC!)",
        ["options_undo_use_different_filterpanels"]                     = "Sichere Undo f√ľr jeden Filter Panel",
        ["options_undo_use_different_filterpanels_TT"]             = "Sichert die Undo Markierungen f√ľr jeden Filter Panel (Inventar, Bank, Mail, etc.) verschieden.\nDeaktiviert werden die Markierungen f√ľr alle gleich gesichert und sind somit √ľberall gleich wiederherstellbar.",
        ["options_research_filter"]		 		 = "Erlaube 'Zur Analyse vorgemerkt'",
        ["options_research_filter_TT"]		 = "Erlaubt 'Zur Analyse vorgemerkte' Gegenst√§nde dennoch im Handwerk Analyse Fenster auszuw√§hlen",
        ["options_icons_description"]       = "In diesem Untermen√ľ k√∂nnen Sie die Markierungssymbole des AddOns konfigurieren.\nEs gibt 3 Typen von Symbolen:\n1. Normal\n2. Ausr√ľstung Sets\n3. Dynamische\nDeren Untermen√ľ zeigt weitere Beschreibungen an.\n\nHinweise:\n-Wenn Markierungssymbol Text rot in Auswahllisten angezeigt wird, so ist dieses Symbol aktuell deaktiviert.\n-Jedes Markierungssymbol ist zun√§chst gesch√ľtzt bis eine Ausnahme (Siehe Untermen√ľ \'Schutz (Anti-Methoden)\') f√ľr normale Symbole aktiviert wird, bzw. dynamische Symbole je Symbol anders konfiguriert werden.",
        ["options_icons_non_gear_sets_description"] = "Normale Symbole sind die Standard Symbole dieses AddOns, welche nur in Farbe/Textur/Gr√∂√üe/Postion ver√§ndert werden k√∂nnen. Dieses sind f√ľr feste Gegebenheiten vorgesehen wie z.B. gegen Verkauf, Zerlegen, Aufwerten besch√ľtzen.\nDiese Standard Symbole m√ľssen aktiviert sein wenn Sie z.B. Automatische Markierungen (die Einstellungen finden Sie im Autoamtische Markierungen Untermen√ľ) nutzen m√∂chte, welche von dem entsprechenden Symbol abh√§ngig sind.\nWenn eine Einstellungsoption nicht aktivierbar ist, versuchen Sie hier das entsprechende Standard Symbol zu aktivieren.",
        ["options_icons_gear_sets_description"]     = "Ausr√ľstung Sets sind die 5 Standard Symbole dieses AddOns, nur in Farbe/Textur/Gr√∂√üe/Postion ver√§ndert werden k√∂nnen. Diese sind f√ľr Ihre Ausr√ľstung vorgesehen.\nWenn Sie mehr Ausr√ľstung Set Symbole ben√∂tigen k√∂nnen Sie eines der bis zu 30 dynamischen Symbole zu einem Ausr√ľstung Set Symbol umfunktionieren.",
        ["options_icons_dynamic"]				 = "Dynamische Symbole",
        ["options_icons_dynamic_usable"]				 =  "Dynamische Symbole - Gesamt verwendbar",
        ["options_icons_dynamic_usable_TT"]				 =  "Setze die Anzahl Dynamische Symbole, welche durch das AddOn maximal verwendet werden darf.",
        ["options_icons_dynamic_usable_warning"]		 =  "Dynamische Symbole sind die nicht-standard Markierungen dieses AddOns welche nicht nur die Farbe/Textur/Gr√∂√üe und Position ver√§ndern k√∂nnen, sondern sogar je Symbol individuell die Besch√ľtz (Anti-*)- und weitere Einstellungen ver√§ndern k√∂nnen. Jedes der bis zu 30 m√∂glichen dynamischen Symbolen kann genau f√ľr deine Belange eingestellt werden.\n\nVer√§ndere hier die maximal verwendbaren Dynamischen Symbole. Je niederiger der Wert, so besser die Einstellungs- und Kontextmen√ľ Performance.\n[|cFF0000ACHTUNG|r]Die Benutzeroberfl√§che wird direkt neu geladen, wenn du diese Option ver√§nderst.\nBitte schau danach auch in den Kontextmen√ľ Einstellugen nach den dynamischen Untermen√ľs, und passe diese an (sofern ben√∂tigt).",

