        ["options_scan_automatic_marks_scan_bag"]           = ">>>Scanne \'%s\' nach automatischen Markierungen...",
        ["options_scan_automatic_marks_scan_bag_finished"]  = "Scan von \'%s\' wurde beendet<<<",
